changeSet.sql:
update multi_trader_account_request
set request_group_id = concat('legacy-', id),
    request_group_index = 1,
    request_group_size = 1
where request_group_id is null;

create index idx_multi_trader_request_group
    on multi_trader_account_request (request_group_id, request_group_index);
create index idx_multi_trader_request_group_status
    on multi_trader_account_request (request_group_id, status);
